    \begin{equation}\label{19}
		TDCS_{av}=\frac{\cos\theta_p}{2\pi}\int^{2\pi}_{0}d\phi_p \frac{d^3\sigma(\mathbf{\Delta})}{d\Omega_{e}d\Omega_{s}dE_{e}}.  
	\end{equation}

